#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $q = new CGI;
my $log_dir = "/path/to/your/logs"; # Define your log directory here

my $filename = $q->param('logfile');

if ($filename =~ /^([-\@\w.]+)$/) {
    $filename = $1;                   
} else {
    die "Bad filename";
}

open(FH, "<", "$log_dir/$filename") or die $!;

print $q->header('text/plain');
while (<FH>) {
    print $_;
}
close(FH);